import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function DashboardPage() {
  const [stats, setStats] = useState({
    total_patients: 0,
    total_reports: 0,
    total_doctors: 0,
    monthly_data: []
  });

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const res = await API.get("/dashboard-stats");
      setStats(res.data);
    } catch (error) {
      console.error("Failed to fetch dashboard stats");
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role={user?.role || "admin"} />

      <div className="main-content">
        <Navbar
          title="Dashboard"
          subtitle="AI Doctor Recommendation System Overview"
        />

        <div className="row g-4 mb-4">
          <div className="col-md-4">
            <div className="dashboard-card text-center">
              <h6 className="text-muted">Total Patients</h6>
              <h2 className="text-primary fw-bold">{stats.total_patients}</h2>
            </div>
          </div>

          <div className="col-md-4">
            <div className="dashboard-card text-center">
              <h6 className="text-muted">Total Reports</h6>
              <h2 className="text-success fw-bold">{stats.total_reports}</h2>
            </div>
          </div>

          <div className="col-md-4">
            <div className="dashboard-card text-center">
              <h6 className="text-muted">Total Doctors</h6>
              <h2 className="text-danger fw-bold">{stats.total_doctors}</h2>
            </div>
          </div>
        </div>

        <div className="dashboard-card">
          <h4 className="mb-3">Monthly Report Activity</h4>

          {stats.monthly_data && stats.monthly_data.length > 0 ? (
            <div className="table-responsive">
              <table className="table table-hover align-middle">
                <thead>
                  <tr>
                    <th>Month</th>
                    <th>Total Reports</th>
                  </tr>
                </thead>
                <tbody>
                  {stats.monthly_data.map((item, index) => (
                    <tr key={index}>
                      <td>{item.month}</td>
                      <td>{item.count}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="alert alert-info rounded-4 mb-0">
              No monthly analytics data available yet.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default DashboardPage;
